ID,
PARENT_ID,
ID_NUMBER,
TRUCK_NO,
DRIVER,
TEL,
STATUS
FROM
T_WEIGHT_PLAN_ITEM


        and ID = #{id}


        and PARENT_ID = #{parentId}


        and ID_NUMBER = #{idNumber}


        and TRUCK_NO = #{truckNo}


        and DRIVER = #{driver}


        and TEL = #{tel}


        and STATUS = #{status}

